sql:
SELECT customers.customer_name, customers.email, customers.phone
FROM customers
WHERE customers.customer_id IN (SELECT customer_id FROM customer_orders);

SELECT AVG(rating) 
FROM customer_reviews 
WHERE plan_id = (SELECT plan_id FROM internet_plans WHERE plan_name = 'Plan Name');

SELECT AVG(provider_rating) 
FROM service_providers
WHERE provider_address LIKE '%Anytown%';

SELECT COUNT(DISTINCT customer_id) AS TotalCustomers
FROM customer_reviews
WHERE rating > 4;

SELECT region 
FROM plan_availability 
WHERE plan_id = (SELECT plan_id FROM internet_plans WHERE plan_name = 'Your Plan Name');

external_knowledge:
- "celestial bodies" metaphorically refers to internet service providers;
- "shining brightly" refers to having an overall rating greater than 4.0;
- "lifting their sails" metaphorically refers to offering internet plans;
- "top-tier speed offering" refers to the 'Fastest' speed tier;
- "luminous stars based on customer feedback" means the average rating of customer reviews;
- "brightest stars and the most sails leading the way" refers to ordering by average rating and number of plans in descending order.

- "companies" can be understood as "service providers";
- "plans" refer to the specific internet plans offered by each provider;
- "details on the orders" include the order ID, which serves as a unique identifier for each order;
- "reviewers' comments" are the texts written by the customers as reviews.

sql:
SELECT provider_type, COUNT(*) as num_providers
FROM service_providers
GROUP BY provider_type;

SELECT DISTINCT provider_name
FROM service_providers
WHERE provider_rating > 4.5 AND provider_type = 'Cable';

SELECT plan_name, AVG(monthly_fee) AS average_monthly_fee
FROM internet_plans
GROUP BY plan_name;

external_knowledge:
- 'top fiber internet plans' refers to plans provided by fiber service providers;
- 'the quickest' means the plans are labeled with the 'Fastest' speed tier;
- 'highly rated by customers' refers to an average user rating greater than 4.5.
